    private InfiniteScrollListInterop? _interop;
    private InfiniteScrollListCallback? _callback;
    private DotNetObjectReference<InfiniteScrollListCallback>? _dotNetRef;
    private bool _isLoading;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _callback = new InfiniteScrollListCallback(HandleSentinelVisible);
            _dotNetRef = DotNetObjectReference.Create(_callback);
            _interop = new InfiniteScrollListInterop(JS);
            await _interop.InitializeAsync(_sentinelRef, _dotNetRef);
        }
    }

    private async Task HandleSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        await InvokeAsync(async () =>
        {
            _isLoading = true;
            StateHasChanged();

            await OnLoadMore.InvokeAsync();

            _isLoading = false;
            StateHasChanged();
        });
    }

    public async ValueTask DisposeAsync()
    {
        if (_interop is not null)
            await _interop.DisposeAsync();

        _dotNetRef?.Dispose();
        _callback?.Dispose();
    }
}

